Question: Which of the following are correct implementation for acquire function ? Assume 0 means UNLOCKED and 1 means LOCKED. Initially l->locked = 0. Options: A) c 
 void acquire(struct lock *l)
 {
 for(;;)
 if(xchg(&l->locked, 1) == 0)
 return;
 } B) c 
 void acquire(struct lock *l)
 {
 if(cas(&l->locked, 0, 1) == 0)
 return;
 } C) c 
 void acquire(struct lock *l)
 {
 for(;;)
 if(cas(&l->locked, 1, 0) == 1)
 return;
 } D) c 
 void acquire(struct lock *l)
 {
 if(l->locked == 0) 
 return;
 }
